{
  "summary": "A procedural smoke trail effect using overlapping, tinted circular particles that expand and fade. It mimics the 'puffy' look of the asset by using high-frequency emission with randomized tints (greys and tans) and a scaling curve that simulates atmospheric expansion.",
  "duration_ms": 1500,
  "palette": [
    "#9D9D9D",
    "#8B8B8B",
    "#7A6E5D",
    "#5E5E5E",
    "#B0A080"
  ],
  "particle_config": {
    "frequency": 35,
    "lifespan": 1500,
    "particle_count": 50,
    "emitter_offset": {
      "x": -20,
      "y": 0
    },
    "velocity": {
      "min": 5,
      "max": 20
    },
    "scale": {
      "start": 0.5,
      "end": 2.2
    },
    "alpha": {
      "start": 0.6,
      "end": 0
    },
    "rotation": {
      "min": 0,
      "max": 360
    },
    "blend_mode": "NORMAL"
  },
  "typescript": "function createRocketTrail(scene: Phaser.Scene, rocket: Phaser.GameObjects.Sprite) {\n  if (!scene.textures.exists('smoke_particle')) {\n    const graphics = scene.make.graphics({ x: 0, y: 0, add: false });\n    graphics.fillStyle(0xffffff);\n    graphics.fillCircle(16, 16, 16);\n    graphics.generateTexture('smoke_particle', 32, 32);\n  }\n\n  const emitter = scene.add.particles(0, 0, 'smoke_particle', {\n    follow: rocket,\n    followOffset: { x: -rocket.width / 2, y: 0 },\n    frequency: 35,\n    lifespan: 1500,\n    speed: { min: 5, max: 15 },\n    angle: { min: 0, max: 360 },\n    scale: { start: 0.6, stop: 2.2 },\n    alpha: { start: 0.6, stop: 0 },\n    tint: [0x9d9d9d, 0x8b8b8b, 0x7a6e5d, 0x5e5e5e, 0xb0a080],\n    rotate: { min: 0, max: 360 },\n    blendMode: 'NORMAL',\n    onParticleEmit: (particle) => {\n      particle.rotation = Math.random() * Math.PI * 2;\n    }\n  });\n\n  return emitter;\n}"
}
}
